using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    Models.SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that scores sentences by word-frequency relevance
/// and returns the top-ranked sentences in their original order.
/// </summary>
public partial class ExtractiveSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords =
    [
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","of","in","to","for",
        "with","on","at","from","by","about","as","into","through","during",
        "before","after","above","below","between","out","off","over","under",
        "again","further","then","once","here","there","when","where","why",
        "how","all","each","every","both","few","more","most","other","some",
        "such","no","nor","not","only","own","same","so","than","too","very",
        "just","because","this","that","these","those","it","its","i","me",
        "my","we","our","you","your","he","him","his","she","her","they",
        "them","their","what","which","who","whom"
    ];

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);

        if (sentences.Count == 0)
            return new SummarizeResponse { Summary = string.Empty, OriginalSentenceCount = 0, SummarySentenceCount = 0 };

        if (sentences.Count <= maxSentences)
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences, preserving original order.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i]).ToList();

        return new SummarizeResponse
        {
            Summary = string.Join(" ", summarySentences),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = summarySentences.Count
        };
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (StopWords.Contains(word.ToLowerInvariant()) || word.Length < 2)
                    continue;

                var lower = word.ToLowerInvariant();
                freq[lower] = freq.GetValueOrDefault(lower) + 1;
            }
        }

        // Normalize by max frequency.
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys.ToList())
                freq[key] /= max;
        }

        return freq;
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, double> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            double score = words
                .Where(w => w.Length >= 2)
                .Sum(w => wordFrequencies.GetValueOrDefault(w.ToLowerInvariant()));

            // Normalize by word count to avoid biasing toward longer sentences.
            var meaningfulWords = words.Count(w => w.Length >= 2);
            scores.Add(meaningfulWords > 0 ? score / meaningfulWords : 0);
        }

        return scores;
    }

    private static string[] Tokenize(string text) => WordTokenizer().Split(text);

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\W+", RegexOptions.Compiled)]
    private static partial Regex WordTokenizer();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(IDocumentSummarizer summarizer) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Post([FromBody] SummarizeRequest request)
    {
        var result = summarizer.Summarize(request.Text, request.MaxSentences);
        return Ok(result);
    }
}

